create function password_work_factor_timings(iterations int default 3, timeout_ms double precision default 1500)
    returns table
            (
                algorithm       hashing_algorithm,
                work_factor     int,
                iteration       int,
                time_elapsed_ms double precision
            )
    language plpgsql
    parallel safe
as
$$
declare
    current_work_factor int;
    current_iteration   int;
    start_time          timestamp;
    end_time            timestamp;
begin
    -- bcrypt
    algorithm := 'bcrypt';

    for current_work_factor in 10..31
        loop
            for current_iteration in 1..iterations
                loop
                    work_factor := current_work_factor;
                    iteration := current_iteration;
                    start_time := clock_timestamp();
                    perform omni_auth.hash_password('password', hashing_algorithm => algorithm,
                                                    work_factor => current_work_factor);
                    end_time := clock_timestamp();
                    time_elapsed_ms := (extract(epoch from end_time) - extract(epoch from start_time)) * 1000;
                    if time_elapsed_ms >= timeout_ms then
                        return;
                    end if;
                    return next;
                end loop;
        end loop;
    return;

end;
$$;

create procedure _postgrest_relation(request omni_httpd.http_request,
                                     relation inout regclass,
                                     namespace inout text,
                                     settings postgrest_settings default postgrest_settings())
    language plpgsql
as
$$
declare
    saved_search_path text := current_setting('search_path');
begin

    if request.method = 'GET' then
        namespace := omni_http.http_header_get(request.headers, 'accept-profile');
    end if;

    if request.method in ('POST', 'PATCH') then
        namespace := omni_http.http_header_get(request.headers, 'content-profile');
    end if;

    if namespace is null and cardinality(settings.schemas) > 0 then
        namespace := settings.schemas[1]::text;
    end if;

    if namespace is null then
        return;
    end if;

    if not namespace::name = any (settings.schemas) then
        relation := null;
        namespace := null;
        return;
    end if;

    perform set_config('search_path', namespace, true);

    relation := to_regclass(split_part(request.path, '/', 2));
    if relation is null or relation::text like 'pg_%' then
        relation := null;
        return;
    end if;

    perform set_config('search_path', saved_search_path, false);

end;
$$;

DO $$
declare
citus_schemas_create_query text;
BEGIN
citus_schemas_create_query=$CSCQ$
    CREATE OR REPLACE VIEW %I.citus_schemas AS
    SELECT
        ts.schemaid::regnamespace AS schema_name,
        ts.colocationid AS colocation_id,
        CASE
            WHEN pg_catalog.has_schema_privilege(CURRENT_USER, ts.schemaid::regnamespace, 'USAGE')
            THEN pg_size_pretty(coalesce(schema_sizes.schema_size, 0))
            ELSE NULL
        END AS schema_size,
        pg_get_userbyid(n.nspowner) AS schema_owner
    FROM
        pg_dist_schema ts
    JOIN
        pg_namespace n ON (ts.schemaid = n.oid)
    LEFT JOIN (
        SELECT c.relnamespace::regnamespace schema_id, SUM(size) AS schema_size
        FROM citus_shard_sizes() css, pg_dist_shard ds, pg_class c
        WHERE css.shard_id = ds.shardid AND ds.logicalrelid = c.oid
        GROUP BY schema_id
    ) schema_sizes ON schema_sizes.schema_id = ts.schemaid
    ORDER BY
        schema_name;
$CSCQ$;

IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'public') THEN
    EXECUTE format(citus_schemas_create_query, 'public');
    REVOKE ALL ON public.citus_schemas FROM public;
    GRANT SELECT ON public.citus_schemas TO public;
ELSE
    EXECUTE format(citus_schemas_create_query, 'citus');
    ALTER VIEW citus.citus_schemas SET SCHEMA pg_catalog;
    REVOKE ALL ON pg_catalog.citus_schemas FROM public;
    GRANT SELECT ON pg_catalog.citus_schemas TO public;
END IF;

END;
$$;

